import fs from 'node:fs';
import path from 'node:path';

const PACKAGE_JSON_PATH = path.join(import.meta.dirname, '..', 'package.json');

function getRegistry() {
  try {
    if (!fs.existsSync(PACKAGE_JSON_PATH)) {
      console.error('Error: package.json file not found');
      process.exit(1);
    }

    const packageJson = JSON.parse(fs.readFileSync(PACKAGE_JSON_PATH, 'utf8'));
    const registry = packageJson.publishConfig?.registry;

    if (!registry) {
      console.error('Error: publishConfig.registry not found in package.json');
      process.exit(1);
    }

    return registry;
  } catch (error) {
    console.error('Error reading registry from package.json:', error.message);
    process.exit(1);
  }
}

export function getRegistryNamespace() {
  const registry = getRegistry();
  const registryUrl = new URL(registry);
  const passwordKey = `//${registryUrl.host}${registryUrl.pathname}`;
  return passwordKey;
}
